import{c as e,Q as l,j as a,m as n}from"./chunks/framework.CQqJojvj.js";const c=JSON.parse('{"title":"RAG 项目 — AI 面试助手","description":"","frontmatter":{},"headers":[],"relativePath":"projects/rag-project.md","filePath":"projects/rag-project.md","lastUpdated":null}'),s={name:"projects/rag-project.md"};function r(o,t,i,d,g,p){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="rag-项目-—-ai-面试助手" tabindex="-1">RAG 项目 — AI 面试助手 <a class="header-anchor" href="#rag-项目-—-ai-面试助手" aria-label="Permalink to &quot;RAG 项目 — AI 面试助手&quot;">​</a></h1><blockquote><p>基于 Spring AI + pgvector 的 AI 面试助手平台，集成简历分析、模拟面试、RAG 知识库问答。</p></blockquote><hr><h2 id="全局认知" tabindex="-1">全局认知 <a class="header-anchor" href="#全局认知" aria-label="Permalink to &quot;全局认知&quot;">​</a></h2><h3 id="业务架构" tabindex="-1">业务架构 <a class="header-anchor" href="#业务架构" aria-label="Permalink to &quot;业务架构&quot;">​</a></h3><p><strong>用户痛点：</strong></p><ul><li><strong>简历质量难把控</strong> — ToC 求职者不清楚自己简历的问题，ToB HR 筛选简历效率低</li><li><strong>面试准备无针对性</strong> — 通用面试题与实际简历不匹配，缺乏个性化练习</li><li><strong>技术文档检索难</strong> — 企业/项目内部知识分散，查询答案耗时</li></ul><p><strong>解决方案：AI 面试助手</strong></p><ul><li>简历管理（多格式上传、AI分析评分、改进建议、PDF报告导出）</li><li>模拟面试（AI 智能出题、实时问答交互、答案智能评估、面试报告生成）</li><li>知识库问答（文档上传与向量化、RAG检索增强、多轮对话问答、SSE流式响应）</li></ul><h3 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to &quot;技术架构&quot;">​</a></h3><p><strong>核心数据流向</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">场景</th><th style="text-align:left;">数据流向</th><th style="text-align:left;">关键技术</th></tr></thead><tbody><tr><td style="text-align:left;">简历上传分析</td><td style="text-align:left;">上传 → 文件解析(Tika) → MinIO存储 → Stream入队 → AI分析 → 结果入库</td><td style="text-align:left;">异步解耦、文件Hash去重</td></tr><tr><td style="text-align:left;">模拟面试</td><td style="text-align:left;">创建会话(Redis缓存) → AI出题 → 答题 → 分批评估 → 生成报告</td><td style="text-align:left;">分批处理防Token溢出</td></tr><tr><td style="text-align:left;">RAG问答</td><td style="text-align:left;">Query向量化 → pgvector相似度检索 → 上下文构建 → LLM生成 → SSE流式返回</td><td style="text-align:left;">RAG检索增强</td></tr></tbody></table><h3 id="电梯演讲" tabindex="-1">电梯演讲 <a class="header-anchor" href="#电梯演讲" aria-label="Permalink to &quot;电梯演讲&quot;">​</a></h3><p><strong>开场（10秒）：</strong> &quot;我独立开发了一个智能 AI 面试助手平台，帮助求职者和 HR 解决简历评估与面试准备的痛点。&quot;</p><p><strong>技术亮点（90秒）：</strong></p><blockquote><p>&quot;技术选型上采用 Spring Boot 3 + Java 21 + Spring AI 构建后端，前端用 React + TypeScript。四个核心亮点：</p><ol><li><strong>异步解耦设计</strong> — 简历分析、知识库向量化等耗时操作采用 Redis Stream 异步处理，避免 AI 调用阻塞用户请求，支持任务失败自动重试</li><li><strong>RAG 检索增强</strong> — 基于 pgvector 实现向量检索，无需引入额外向量数据库；动态调整 TopK 和相似度阈值，自动扩展提高召回率</li><li><strong>流式交互体验</strong> — 基于 SSE 实现打字机效果的流式响应，减少用户等待焦虑</li><li><strong>稳定性保障</strong> — 面试评估采用分批处理策略（每批8题），规避大模型 Token 溢出风险；注解式限流组件防止 API 滥用&quot;</li></ol></blockquote><hr><h2 id="模块拆解" tabindex="-1">模块拆解 <a class="header-anchor" href="#模块拆解" aria-label="Permalink to &quot;模块拆解&quot;">​</a></h2><h3 id="简历管理模块" tabindex="-1">简历管理模块 <a class="header-anchor" href="#简历管理模块" aria-label="Permalink to &quot;简历管理模块&quot;">​</a></h3><p><strong>核心流程：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>上传 → Tika解析 → MinIO存储 → Hash去重 → Redis Stream入队</span></span>
<span class="line"><span>→ Consumer消费 → AI分析 → 结果入库 → 用户查看报告</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>关键技术实现：</strong></p><ol><li><strong>文件解析（Apache Tika）</strong> — 支持 PDF/DOCX/DOC/TXT/MD，自定义 <code>NoOpEmbeddedDocumentExtractor</code> 禁用嵌入资源解析避免提取PDF图片引用，<code>SortByPosition</code> 优化多栏布局</li><li><strong>异步处理（Redis Stream）</strong> — 继承 <code>AbstractStreamConsumer</code>，专注业务逻辑，支持失败重试（最多3次）</li><li><strong>限流保护</strong> — Redis + Lua 滑动窗口算法，<code>@RateLimit</code> 注解式使用，支持 GLOBAL + IP + USER 多维度</li><li><strong>结构化 Prompt</strong> — System Prompt 定义角色和评分标准，<code>BeanOutputConverter</code> 强制 AI 返回 JSON 映射到 DTO</li><li><strong>文件 Hash 去重</strong> — MD5 计算文件指纹，避免重复上传浪费 AI 调用成本</li></ol><p><strong>面试话术：</strong></p><blockquote><p>&quot;使用 Apache Tika 实现多格式文档解析时，我遇到了一个生产环境问题——PDF 中的图片被解析成了临时文件路径。解决方案是自定义 NoOpEmbeddedDocumentExtractor 禁用嵌入资源解析，只提取纯文本，同时设置 SortByPosition 优化多栏布局的文本顺序。&quot;</p></blockquote><h3 id="模拟面试模块" tabindex="-1">模拟面试模块 <a class="header-anchor" href="#模拟面试模块" aria-label="Permalink to &quot;模拟面试模块&quot;">​</a></h3><p><strong>问题类型权重分配（后端面试）：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">类别</th><th style="text-align:center;">权重</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">项目经历</td><td style="text-align:center;">20%</td><td style="text-align:left;">深挖项目中的技术决策</td></tr><tr><td style="text-align:left;">MySQL</td><td style="text-align:center;">20%</td><td style="text-align:left;">索引、事务、SQL优化</td></tr><tr><td style="text-align:left;">Redis</td><td style="text-align:center;">20%</td><td style="text-align:left;">数据结构、缓存策略</td></tr><tr><td style="text-align:left;">Java基础</td><td style="text-align:center;">10%</td><td style="text-align:left;">集合、反射、泛型</td></tr><tr><td style="text-align:left;">集合</td><td style="text-align:center;">10%</td><td style="text-align:left;">HashMap、ConcurrentHashMap</td></tr><tr><td style="text-align:left;">并发</td><td style="text-align:center;">10%</td><td style="text-align:left;">线程池、锁、AQS</td></tr></tbody></table><p><strong>核心设计：</strong></p><ol><li><strong>分类配比</strong> — 按权重分配各类问题数量，贴近真实面试</li><li><strong>历史去重</strong> — 传入历史问题列表，Prompt 中要求避免重复</li><li><strong>追问机制</strong> — 每个主问题配置 1-2 条追问，构建线性追问流</li><li><strong>分批评估</strong> — 每批 8 题独立调用 AI，避免单次 Token 超限，最后二次汇总生成整体评价</li><li><strong>断点续面</strong> — 会话 Redis 缓存 24h，支持从数据库恢复</li></ol><p><strong>面试话术（分批评估）：</strong></p><blockquote><p>&quot;答案评估最大的挑战是 Token 溢出。假设一份简历有 20 道题，每道题的回答平均 500 字，加上简历本身和 Prompt，总 Token 可能超过 8k，超出模型限制。我的解决方案是 &#39;分批评估 + 二次汇总&#39;：将问题按每批 8 题分组，每批独立调用 AI 评估，合并各批次评估结果后，再调用一次 AI 对整体表现进行汇总（strengths、improvements、overallFeedback）。这样即使 50 道题也能稳定评估。&quot;</p></blockquote><h3 id="rag-知识库模块" tabindex="-1">RAG 知识库模块 <a class="header-anchor" href="#rag-知识库模块" aria-label="Permalink to &quot;RAG 知识库模块&quot;">​</a></h3><p><strong>知识库上传与向量化流程：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>文档上传 → Tika 文本提取 → TokenTextSplitter 分块(500 tokens/chunk)</span></span>
<span class="line"><span>→ 分批调用 Embedding API (1024维) → pgvector 向量存储</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>RAG 问答流程：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户提问 → Query Rewrite(短查询扩展) → 向量相似度检索 → 有效性校验</span></span>
<span class="line"><span>→ Prompt 拼接(问题+检索文档) → SSE 流式返回</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>检索优化策略：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">优化点</th><th style="text-align:left;">实现</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>动态检索参数</strong></td><td style="text-align:left;">短查询 TopK=20/相似度=0.18（提高召回），长查询 TopK=8/相似度=0.28（提高精度）</td></tr><tr><td style="text-align:left;"><strong>Query Rewrite</strong></td><td style="text-align:left;">&quot;Redis&quot; → &quot;Redis 的数据结构和常用命令有哪些&quot;，提高检索质量</td></tr><tr><td style="text-align:left;"><strong>有效性校验</strong></td><td style="text-align:left;">短查询(2-20字符)要求检索结果必须包含查询关键词，避免&quot;信息不足&quot;的废话</td></tr><tr><td style="text-align:left;"><strong>探测窗口归一化</strong></td><td style="text-align:left;">先缓冲前 120 字符，识别&quot;无信息&quot;模板则立即返回固定短句</td></tr><tr><td style="text-align:left;"><strong>多知识库联合检索</strong></td><td style="text-align:left;"><code>filter: kb_id IN [&#39;1&#39;, &#39;2&#39;]</code> 跨文档问答</td></tr></tbody></table><p><strong>为什么用 pgvector 而不是专用向量数据库？</strong></p><blockquote><p>&quot;架构精简，不引入新组件；PG 的向量功能已满足需求（HNSW 索引，千万级向量检索 ms 级）；事务一致性（向量和业务数据在一个数据库）&quot;</p></blockquote><h3 id="ai-配置管理" tabindex="-1">AI 配置管理 <a class="header-anchor" href="#ai-配置管理" aria-label="Permalink to &quot;AI 配置管理&quot;">​</a></h3><p><strong>多平台适配：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">实现方式</th></tr></thead><tbody><tr><td style="text-align:left;">配置存储</td><td style="text-align:left;">PostgreSQL 持久化 + AES 加密 API Key</td></tr><tr><td style="text-align:left;">工厂模式</td><td style="text-align:left;"><code>AiChatClientFactory</code> 统一创建 ChatClient，封装不同平台差异</td></tr><tr><td style="text-align:left;">动态加载</td><td style="text-align:left;">运行时从 DB 读取配置创建客户端，无需重启</td></tr><tr><td style="text-align:left;">兼容封装</td><td style="text-align:left;">Spring AI 的 OpenAI 兼容模式，一套代码适配阿里云 DashScope、Moonshot、DeepSeek</td></tr></tbody></table><hr><h2 id="面试重点" tabindex="-1">面试重点 <a class="header-anchor" href="#面试重点" aria-label="Permalink to &quot;面试重点&quot;">​</a></h2><h3 id="高频问题" tabindex="-1">高频问题 <a class="header-anchor" href="#高频问题" aria-label="Permalink to &quot;高频问题&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">问题</th><th style="text-align:left;">回答要点</th></tr></thead><tbody><tr><td style="text-align:left;">&quot;为什么 AI 分析要异步？&quot;</td><td style="text-align:left;">AI 调用耗时 3-10 秒，同步会阻塞用户请求；异步提升用户体验，支持失败重试</td></tr><tr><td style="text-align:left;">&quot;如何保证分析不丢失？&quot;</td><td style="text-align:left;">Redis Stream 持久化；消费者 ACK 确认；失败自动重试（最多3次）</td></tr><tr><td style="text-align:left;">&quot;限流是怎么实现的？&quot;</td><td style="text-align:left;">Redis + Lua 滑动窗口；原子操作避免竞态；多维度组合；注解式使用，零侵入</td></tr><tr><td style="text-align:left;">&quot;分批评估的具体策略？&quot;</td><td style="text-align:left;">默认每批8题；多轮调用 AI；合并后二次汇总生成整体评价</td></tr><tr><td style="text-align:left;">&quot;如何防止重复提问？&quot;</td><td style="text-align:left;">查询历史问题列表传入 Prompt；AI 生成时明确要求避免重复</td></tr><tr><td style="text-align:left;">&quot;为什么用 pgvector？&quot;</td><td style="text-align:left;">架构精简；PG HNSW 索引性能足够；事务一致性</td></tr></tbody></table><h3 id="亮点数据" tabindex="-1">亮点数据 <a class="header-anchor" href="#亮点数据" aria-label="Permalink to &quot;亮点数据&quot;">​</a></h3><ul><li>向量维度：1024（text-embedding-v3）</li><li>分块大小：500 tokens/块，重叠 50 tokens</li><li>动态 TopK：短查询 20、中查询 12、长查询 8</li><li>相似度阈值：短查询 0.18、其他 0.28</li><li>分批评估：每批 8 题（可配置）</li><li>缓存 TTL：24 小时</li><li>支持文件格式：PDF/DOCX/DOC/TXT/MD</li><li>文件限制：最大 10MB</li></ul><h3 id="可能的追问" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问" aria-label="Permalink to &quot;可能的追问&quot;">​</a></h3><p><strong>Q: 如果 AI 服务挂了怎么办？</strong></p><blockquote><p>&quot;Consumer 会捕获异常，标记任务为 FAILED，并保存错误信息。用户可以在前端看到失败状态，点击&#39;重新分析&#39;按钮手动触发重试。同时我们预留了降级策略的扩展点，可以对接本地 Ollama 模型作为备用。&quot;</p></blockquote><p><strong>Q: 如何防止用户刷接口？</strong></p><blockquote><p>&quot;上传接口有 @RateLimit 注解，限制每个 IP 每分钟最多 5 次。使用 Redis + Lua 实现滑动窗口，相比固定窗口更平滑，避免窗口边界突发流量。&quot;</p></blockquote><p><strong>Q: RAG 检索失败怎么办？</strong></p><blockquote><p>&quot;有 fallback 机制。如果带过滤条件的检索失败（可能是表达式语法问题），会降级到全量检索，然后在内存中过滤 kb_id，保证功能可用性。检索无结果时探测窗口识别并返回固定提示，避免大模型生成无意义的拒答。&quot;</p></blockquote><hr>`,58)])])}const u=e(s,[["render",r]]);export{c as __pageData,u as default};
